-- Откат: вернуть прежний текст части 5 (с дублированием)
UPDATE lesson_content_chunks
SET body_text = 'Роль SRE в российских компаниях. В большинстве российских компаний SRE — это улучшенный сисадмин. Типичная картина: компания переименовывает отдел эксплуатации, добавляет Kubernetes и объявляет, что у неё теперь SRE. Зрелые компании строят полноценные SRE-практики: SLO, error budgets, on-call, blameless postmortems. Проблемы рынка: дефицит кадров, размытость роли, культура постмортемов, санкционное давление. Российское SRE-сообщество активно развивается: курсы, конференции, Telegram-чаты. Должен ли SRE программировать? Консенсус: SRE должен уметь программировать с акцентом на управление ресурсами, отказоустойчивый код, наблюдаемость и возможность отката. YAML и HCL — не считаются; LeetCode для SRE — перебор. Модели распределения: выделенная SRE команда, embedded SRE, SRE чемпион из разработчиков, эволюционная модель. Главное правило: «Главное — не НЕ упасть. Главное — быстро локализовать и подняться.» Абсолютная надёжность невозможна и не нужна; нужен осознанный выбор уровня и культура быстрого восстановления.'
WHERE lesson_id IN (
  SELECT l.id FROM lessons l
  JOIN modules m ON m.id = l.module_id AND m.slug = 'foundations'
  WHERE l.title = 'Что такое SRE и зачем'
)
AND chunk_index = 5;
